import { useRef, useState } from 'react'
import { useParams } from 'react-router-dom'
import html2canvas from 'html2canvas'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const mockupRef = useRef(null)

  /*
    =====================================
    KEEP RED BOX FOR ALIGNMENT
    =====================================
  */

  const DEV_MODE = true

  /*
    =====================================
    PIXELS PER INCH
    =====================================
  */

  const PIXELS_PER_INCH = 20

  /*
    =====================================
    PRODUCT
    =====================================
  */

  const { id } = useParams()

  const product =
    printProducts.find(
      item => item.id === id
    )

  /*
    =====================================
    LOCKED PRESETS
    =====================================
  */

  const FRONT_PRESET = {

    x: 50.25,
    y: 41.5,

    widthInches: 11.5,
    heightInches: 11.5
  }

  const LEFT_CHEST_PRESET = {

    x: 58.15,
    y: 28.9,

    widthInches: 3.5,
    heightInches: 3.25
  }

  const BACK_PRESET = {

    x: 50.25,
    y: 41.5,

    widthInches: 11.5,
    heightInches: 11.5
  }

  /*
    =====================================
    PRESETS
    =====================================
  */

  const presetMap = {

    front:
      FRONT_PRESET,

    'left-chest':
      LEFT_CHEST_PRESET,

    back:
      BACK_PRESET
  }

  /*
    =====================================
    STATES
    =====================================
  */

  const [selectedColor, setSelectedColor] =
    useState(
      product.colors[0]
    )

  /*
    =====================================
    TRUE MULTI LOGO SYSTEM
    =====================================
  */

  const [frontLogo, setFrontLogo] =
    useState(null)

  const [leftChestLogo, setLeftChestLogo] =
    useState(null)

  const [backLogo, setBackLogo] =
    useState(null)

  const [activePreset, setActivePreset] =
    useState('front')

  /*
    =====================================
    SEPARATE SCALE MEMORY
    =====================================
  */

  const [frontScale, setFrontScale] =
    useState(100)

  const [leftChestScale, setLeftChestScale] =
    useState(100)

  const [backScale, setBackScale] =
    useState(100)

  /*
    =====================================
    CURRENTS
    =====================================
  */

  const currentPreset =
    presetMap[activePreset]

  const currentLogo =
    activePreset === 'front'
      ? frontLogo
      : activePreset === 'left-chest'
      ? leftChestLogo
      : backLogo

  const currentScale =
    activePreset === 'front'
      ? frontScale
      : activePreset === 'left-chest'
      ? leftChestScale
      : backScale

  /*
    =====================================
    SIZE
    =====================================
  */

  const currentWidthPx =
    currentPreset.widthInches *
    PIXELS_PER_INCH

  const currentHeightPx =
    currentPreset.heightInches *
    PIXELS_PER_INCH

  /*
    =====================================
    CLEAN WHITE BACKGROUND REMOVAL
    =====================================
  */

  const removeWhiteBackground = (
    imageUrl,
    callback
  ) => {

    const img =
      new Image()

    img.crossOrigin =
      'anonymous'

    img.onload = () => {

      const canvas =
        document.createElement(
          'canvas'
        )

      canvas.width =
        img.width

      canvas.height =
        img.height

      const ctx =
        canvas.getContext('2d')

      ctx.drawImage(
        img,
        0,
        0
      )

      const imageData =
        ctx.getImageData(
          0,
          0,
          canvas.width,
          canvas.height
        )

      const data =
        imageData.data

      for (
        let i = 0;
        i < data.length;
        i += 4
      ) {

        const r =
          data[i]

        const g =
          data[i + 1]

        const b =
          data[i + 2]

        /*
          REMOVE WHITE
        */

        if (
          r > 240 &&
          g > 240 &&
          b > 240
        ) {

          data[i + 3] = 0
        }
      }

      ctx.putImageData(
        imageData,
        0,
        0
      )

      callback(
        canvas.toDataURL(
          'image/png'
        )
      )
    }

    img.src =
      imageUrl
  }

  /*
    =====================================
    UPLOAD
    =====================================
  */

  const handleUpload = (e) => {

    const file =
      e.target.files[0]

    if (!file) return

    const imageUrl =
      URL.createObjectURL(file)

    removeWhiteBackground(
      imageUrl,
      (cleanedImage) => {

        if (
          activePreset === 'front'
        ) {

          setFrontLogo(
            cleanedImage
          )
        }

        if (
          activePreset === 'left-chest'
        ) {

          setLeftChestLogo(
            cleanedImage
          )
        }

        if (
          activePreset === 'back'
        ) {

          setBackLogo(
            cleanedImage
          )
        }
      }
    )
  }

  /*
    =====================================
    SCALE UPDATE
    =====================================
  */

  const updateScale = (value) => {

    if (
      activePreset === 'front'
    ) {

      setFrontScale(value)
    }

    if (
      activePreset === 'left-chest'
    ) {

      setLeftChestScale(value)
    }

    if (
      activePreset === 'back'
    ) {

      setBackScale(value)
    }
  }

  /*
    =====================================
    REMOVE LOGO
    =====================================
  */

  const removeLogo = () => {

    if (
      activePreset === 'front'
    ) {

      setFrontLogo(null)
    }

    if (
      activePreset === 'left-chest'
    ) {

      setLeftChestLogo(null)
    }

    if (
      activePreset === 'back'
    ) {

      setBackLogo(null)
    }
  }

  /*
    =====================================
    EXPORT
    =====================================
  */

  const exportMockup = async () => {

    const canvas =
      await html2canvas(
        mockupRef.current,
        {
          backgroundColor: null,
          scale: 3,
          useCORS: true
        }
      )

    const image =
      canvas.toDataURL(
        'image/png'
      )

    const link =
      document.createElement(
        'a'
      )

    link.href = image

    link.download =
      `mockup-${activePreset}.png`

    link.click()
  }

  return (

    <div className="h-screen bg-black text-white overflow-hidden">

      <div className="grid grid-cols-1 xl:grid-cols-[65%_35%] h-full">

        {/* =====================================
            MOCKUP
        ===================================== */}

        <div
          ref={mockupRef}
          className="bg-[#e7e7e7] flex items-center justify-center relative overflow-hidden"
        >

          {/* LIGHTING */}

          <div
            className="absolute inset-0 pointer-events-none"
            style={{

              background:
                `
                radial-gradient(
                  circle at center,
                  rgba(255,255,255,0.55) 0%,
                  rgba(0,0,0,0.08) 100%
                )
                `
            }}
          />

          {/* SHIRT */}

          <div className="relative">

            <img
              src={
                activePreset === 'back'
                  ? selectedColor.backImage
                  : selectedColor.image
              }
              alt="shirt"
              className="w-full max-w-[700px] max-h-[88vh] object-contain relative z-20"
              style={{

                filter:
                  `
                  drop-shadow(
                    0px 20px 25px rgba(0,0,0,0.28)
                  )
                  `
              }}
            />

            {/* DESIGN */}

            <div
              className="absolute z-30 overflow-hidden flex items-start justify-center"
              style={{

                width:
                  `${currentWidthPx}px`,

                height:
                  `${currentHeightPx}px`,

                top:
                  `${currentPreset.y}%`,

                left:
                  `${currentPreset.x}%`,

                transform:
                  'translate(-50%, -50%)',

                border:
                  DEV_MODE
                    ? '2px solid red'
                    : 'none'
              }}
            >

              {currentLogo && (

                <img
                  src={currentLogo}
                  alt="design"
                  draggable={false}
                  className="pointer-events-none select-none"
                  style={{

                    width: '100%',

                    height: '100%',

                    objectFit:
                      'contain',

                    /*
                      SUBTLE FABRIC BLEND
                    */

                    mixBlendMode:
                      'multiply',

                    opacity: 0.97,

                    filter:
                      `
                      contrast(1.03)
                      saturate(1.02)
                      `,

                    transform:
                      `scale(${currentScale / 100})`,

                    transformOrigin:
                      'center center'
                  }}
                />

              )}

            </div>

            {/* FABRIC OVERLAY */}

            <div
              className="absolute inset-0 z-40 pointer-events-none"
              style={{

                background:
                  `
                  linear-gradient(
                    to bottom,
                    rgba(255,255,255,0.04),
                    rgba(0,0,0,0.10)
                  )
                  `,

                mixBlendMode:
                  'soft-light'
              }}
            />

          </div>

        </div>

        {/* =====================================
            RIGHT PANEL
        ===================================== */}

        <div className="bg-black border-l border-[#1d1d1d] overflow-y-auto">

          {/* HEADER */}

          <div className="border-b border-[#1d1d1d] p-6">

            <p className="text-yellow-500 text-[10px] tracking-[0.3em] uppercase mb-2">
              Inspired By God
            </p>

            <h1 className="text-4xl font-black">
              {product.name}
            </h1>

          </div>

          {/* CONTENT */}

          <div className="p-6 space-y-6">

            {/* COLORS */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Shirt Colors
              </h2>

              <div className="grid grid-cols-2 gap-3">

                {product.colors.map(
                  color => (

                    <button
                      key={color.name}
                      onClick={() =>
                        setSelectedColor(
                          color
                        )
                      }
                      className={`p-4 rounded-xl text-xs font-black capitalize ${
                        selectedColor.name ===
                        color.name
                          ? 'bg-yellow-500 text-black'
                          : 'bg-[#111] border border-[#222]'
                      }`}
                    >
                      {color.name}
                    </button>

                  )
                )}

              </div>

            </div>

            {/* PLACEMENT */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Placement
              </h2>

              <div className="grid gap-3">

                {[
                  'front',
                  'left-chest',
                  'back'
                ].map(
                  item => (

                    <button
                      key={item}
                      onClick={() =>
                        setActivePreset(
                          item
                        )
                      }
                      className={`p-4 rounded-xl text-xs font-black capitalize ${
                        activePreset === item
                          ? 'bg-yellow-500 text-black'
                          : 'bg-[#111] border border-[#222]'
                      }`}
                    >
                      {item}
                    </button>

                  )
                )}

              </div>

            </div>

            {/* SAVED LAYERS */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Saved Designs
              </h2>

              <div className="grid grid-cols-3 gap-3">

                {[
                  {
                    name: 'front',
                    image: frontLogo
                  },
                  {
                    name: 'left',
                    image: leftChestLogo
                  },
                  {
                    name: 'back',
                    image: backLogo
                  }
                ].map(layer => (

                  <div
                    key={layer.name}
                    className="bg-[#111] border border-[#222] rounded-xl h-[80px] flex items-center justify-center overflow-hidden"
                  >

                    {layer.image ? (

                      <img
                        src={layer.image}
                        alt={layer.name}
                        className="max-h-full object-contain"
                      />

                    ) : (

                      <p className="text-[10px] text-white/30 uppercase font-black">
                        {layer.name}
                      </p>

                    )}

                  </div>

                ))}

              </div>

            </div>

            {/* UPLOAD */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Upload Design
              </h2>

              <input
                type="file"
                accept="image/png,image/jpeg"
                onChange={
                  handleUpload
                }
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4"
              />

            </div>

            {/* REMOVE */}

            {currentLogo && (

              <button
                onClick={
                  removeLogo
                }
                className="w-full border border-red-500 text-red-500 py-4 rounded-xl text-xs font-black"
              >
                REMOVE DESIGN
              </button>

            )}

            {/* EXPORT */}

            <button
              onClick={
                exportMockup
              }
              className="w-full bg-white text-black py-4 rounded-xl text-xs font-black"
            >
              EXPORT MOCKUP
            </button>

            {/* SCALE */}

            <div>

              <div className="flex justify-between mb-3">

                <p className="text-xs text-white/60">
                  Zoom
                </p>

                <p className="text-xs text-yellow-500 font-black">
                  {currentScale}%
                </p>

              </div>

              <input
                type="range"
                min="50"
                max="180"
                value={currentScale}
                onChange={(e) =>
                  updateScale(
                    e.target.value
                  )
                }
                className="w-full"
              />

            </div>

          </div>

        </div>

      </div>

    </div>

  )
}
